head.script:
//==================================================================================================================
// id       : op_203_01_03b 
// 이름     : 사유화차신청등록
// 경로     : 물류/작업계획/철송/
// 작 성 자 : 조성빈
// 작 업 일 : 2025-12-23
// 사용계정 : 내부
// 비고     : 
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//            op_203_01_04p(저감액 우선순위 현황) - 저감액 우선순위 버튼 클릭
//==================================================================================================================
scwin.toDay;
scwin.p_signDt;
scwin.p_dptStnCd;
scwin.p_dptStnNm;
scwin.CREATE_AUTH;

scwin.onpageload = function() {
    // 일자
    scwin.toDay = $c.date.getServerDateTime("yyyyMMdd");
    // 신청일자
    scwin.p_signDt = $c.data.getParameter("signDt");
    // 출발역코드
    scwin.p_dptStnCd= $c.data.getParameter("dptStnCd");    
    // 출발역명
    scwin.p_dptStnNm = $c.data.getParameter("dptStnNm");    

    if(scwin.p_signDt == null) scwin.p_signDt = "";
    if(scwin.p_dptStnCd == null) scwin.p_dptStnCd = "";
    if(scwin.p_dptStnNm == null) scwin.p_dptStnNm = "";

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

        scwin.CREATE_AUTH = $p.getFrame().CREATE_AUTH;

        ica_signDt.setValue(scwin.toDay);

        if(!(scwin.p_signDt=="" || scwin.p_signDt == null))     ica_signDt.setValue(scwin.p_signDt);
        if(!(scwin.p_dptStnCd=="" || scwin.p_dptStnCd == null)) ed_begintrainWorkPlaceCd.setValue(scwin.p_dptStnCd);
        if(!(scwin.p_dptStnNm=="" || scwin.p_dptStnNm == null)) ed_begintrainWorkPlaceNm.setValue(scwin.p_dptStnNm);

        ica_signDt.focus();

        // $c.gus.cfDisableBtn([bSave]);

        // $p.setTimeout(function() {
        //     // ica_signDt.setValue("20250101");
        //     // ed_begintrainWorkPlaceCd.setValue("6R12");
        //     // ica_signDt.setValue("20070728");
        //     // ed_begintrainWorkPlaceCd.setValue("3R02");
        //     ica_signDt.setValue("20250714");
        //     ed_begintrainWorkPlaceCd.setValue("5R15");
        //     ed_begintrainWorkPlaceCd.focus();
        //     ed_begintrainWorkPlaceCd.blur();
        // }, {"delay":150});

    }, {"delay":150});
};

//-------------------------------------------------------------------------
// 사유화차등록결과 조회
//-------------------------------------------------------------------------
scwin.f_qeryList = async function (){
    var validate = await $c.gus.cfValidate([ica_signDt,ed_begintrainWorkPlaceCd]);
  	if (!validate) {	// 신청일자, 출발역
  		return;
	}
	if (ed_begintrainWorkPlaceCd.getValue() == ""){
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002,["출발역"]);
        ed_begintrainWorkPlaceCd.focus();
        return;
	}
    ds_QueryCondition.set("reqDt", ica_signDt.getValue());   // 신청일자
    ds_QueryCondition.set("dptStn", ed_begintrainWorkPlaceCd.getValue());     // 출발역
    $c.sbm.execute(sbm_RetrieveRailroadWorkPlan);

};

//-------------------------------------------------------------------------
// 저장버튼 처리 
//-------------------------------------------------------------------------
scwin.f_Save = async function (eqCd){
    var confirm  = await $c.win.confirm(MSG_CM_CRM_001);   
    if (confirm){  
        $c.sbm.execute(sbm_SaveRailroadWorkPlan);
    }
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
	$c.gus.cfInitObjects(tbl_search, null);
	ica_signDt.focus();
	ica_signDt.setValue(scwin.toDay);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
  	// 선언부
	switch (disGubun) {
  		case 1:   // 출발역 역명 팝업	
            udc_begintrainWorkPlace.setSelectId('retrieveTrainWorkPlace');
            udc_begintrainWorkPlace.cfCommonPopUp(scwin.udc_begintrainWorkPlace_callBackFunc	// XML상의 SELECT ID	
                                                ,pCode					                        // 화면에서의 ??? Code Element의	Value
                                                ,pName					                        // 화면에서의 ??? Name Element의	Value
                                                ,pClose					                        // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                ,null					                        // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                ,null					                        // Title순서	
                                                ,null					                        // 보여주는 각 컬럼들의 폭	
                                                ,null					                        // 컬럼중에서 숨기는	컬럼 지정	
                                                ,null					                        // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                ,null					                        // POP-UP뛰을때 원도우의	사용자 정의	폭
                                                ,null					                        // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                ,null					                        // 윈도우 위치 Y좌표	
                                                ,null					                        // 윈도우 위치 X좌표
                                                ,null					                        // 중복체크여부	("F")
                                                ,pAllSearch					                    // 전체검색허용여부	("F")
                                                ,"역명조회,작업장코드,작업장명"				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 
        break;
  	}	
};

//-------------------------------------------------------------------------
// 계산 처리 **
//-------------------------------------------------------------------------
scwin.f_internalCal1 = async function(row,colid,olddata) {
    if(colid == "xclsAppCnt20Empty" || colid == "xclsAppCnt20Full"  || colid == "xclsAppCnt40Empty" 
    || colid == "xclsAppCnt40Full"  || colid == "xclsAppCnt45Empty" || colid == "xclsAppCnt45Full"){
        var setVal = parseInt(ds_RailroadWorkPlan.getCellData(row, "xclsAppCnt20Empty")) 
                   + parseInt(ds_RailroadWorkPlan.getCellData(row, "xclsAppCnt20Full"))
                   + (parseInt(ds_RailroadWorkPlan.getCellData(row, "xclsAppCnt40Empty"))
                    + parseInt(ds_RailroadWorkPlan.getCellData(row, "xclsAppCnt40Full"))
                    + parseInt(ds_RailroadWorkPlan.getCellData(row, "xclsAppCnt45Empty"))
                    + parseInt(ds_RailroadWorkPlan.getCellData(row, "xclsAppCnt45Full"))
                   ) * 2

        ds_RailroadWorkPlan.setCellData(row, "xclsTeuSum", setVal);

        if (ds_RailroadWorkPlan.getCellData(row, "dayCapaTeu") != 0 
         && (ds_RailroadWorkPlan.getCellData(row, "xclsTeuSum") > ds_RailroadWorkPlan.getCellData(row,"dayCapaTeu"))) {
            await $c.gus.cfAlertMsg("당일 최대 전용화차 신청량이 초과되었습니다.");
            ds_RailroadWorkPlan.setCellData(row, colid, olddata); 
            return;
        } 	  
        var rowCount = ds_RailroadWorkPlan.getRowCount();
        var sumTeu = 0;
        for(var i = 0 ; i< rowCount ; i++){
            if (ds_RailroadWorkPlan.getCellData(row, "arvStnWrkPlCd") == ds_RailroadWorkPlan.getCellData(i, "arvStnWrkPlCd")) {
                sumTeu = parseInt(sumTeu) + parseInt(ds_RailroadWorkPlan.getCellData(i, "xclsTeuSum"));
            }	
            if (ds_RailroadWorkPlan.getCellData(row, "dayCapaTeu") != 0 
            && (parseInt(sumTeu) > parseInt(ds_RailroadWorkPlan.getCellData(row, "dayCapaTeu")))) {
                await $c.gus.cfAlertMsg("당일 최대 전용화차 신청량이 초과되었습니다.");
                ds_RailroadWorkPlan.setCellData(row, colid, olddata); 
                return;
            } 
        }
    }
};

//-------------------------------------------------------------------------
// 계산 처리 **
//-------------------------------------------------------------------------
scwin.f_internalCal = async function(row, colid, olddata) {
    if (colid == "prvtAppCnt20Empty" || colid == "prvtAppCnt20Full"  || colid == "prvtAppCnt40Empty" 
     || colid == "prvtAppCnt40Full"  || colid == "prvtAppCnt45Empty" || colid == "prvtAppCnt45Full"){
        if( ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt20Empty") > ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt20Empty")) {
	        await $c.gus.cfAlertMsg("규격 20E 계획량보다 신청량이 큽니다.");
            ds_RailroadWorkPlan.setCellData(row, "prvtAppCnt20Empty", ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt20Empty"));
            return;
        }
        if (ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt20Full") > ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt20Full")) {
	        await $c.gus.cfAlertMsg("규격 20F 계획량보다 신청량이 큽니다.");
            ds_RailroadWorkPlan.setCellData(row, "prvtAppCnt20Full", ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt20Full"));
            // return;
        }
        if (ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt40Empty") > ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt40Empty")) {
            // await $c.gus.cfAlertMsg("화차규격 40E 계획량보다 신청량이 큽니다.");
            ds_RailroadWorkPlan.setCellData(row, "prvtAppCnt40Empty", ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt40Empty"));
            // return;
        }
        if (ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt40Full") > ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt40Full")) {
            // await $c.gus.cfAlertMsg("화차규격 40F 계획량보다 신청량이 큽니다.");
            ds_RailroadWorkPlan.setCellData(row, "prvtAppCnt40Full", ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt40Full"));
            // return;
        }
        if (ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt45Empty") > ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt45Empty")) {
            // await $c.gus.cfAlertMsg("화차규격 45E 계획량보다 신청량이 큽니다.");
            ds_RailroadWorkPlan.setCellData(row, "prvtAppCnt45Empty", ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt45Empty"));
            // return;
        }
        if (ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt45Full") > ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt45Full")) {
            // await $c.gus.cfAlertMsg("화차규격 45F 계획량보다 신청량이 큽니다.");
            ds_RailroadWorkPlan.setCellData(row, "prvtAppCnt45Full", ds_RailroadWorkPlan.getCellData(row, "wrkPlanCnt45Full"));
            // return;
        }
    }
    if (colid == "prvtAppCnt20Empty" || colid == "prvtAppCnt20Full"  || colid == "prvtAppCnt40Empty" 
     || colid == "prvtAppCnt40Full"  || colid == "prvtAppCnt45Empty" || colid == "prvtAppCnt45Full") {
        ds_RailroadWorkPlan.setCellData(row, "efSum", parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt20Empty"))
                                                    + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt20Full"))
	                                                + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt40Empty"))
                                                    + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt40Full"))
	                                                + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt45Empty"))
                                                    + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt45Full"))
        );
	    ds_RailroadWorkPlan.setCellData(row, "teuSum", parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt20Empty"))
                                                     + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt20Full"))
	                                                 + (      parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt40Empty"))
                                                            + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt40Full"))
	                                                        + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt45Empty"))
                                                            + parseInt(ds_RailroadWorkPlan.getCellData(row, "prvtAppCnt45Full"))
                                                        ) * 2
        );
    }
};

scwin.udc_begintrainWorkPlace_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_begintrainWorkPlaceNm, ed_begintrainWorkPlaceCd, 1, false);
};

scwin.udc_begintrainWorkPlace_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_begintrainWorkPlaceCd.getValue(), ed_begintrainWorkPlaceNm.getValue(), 'F', 'T');
};

scwin.udc_begintrainWorkPlace_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_begintrainWorkPlaceCd, ed_begintrainWorkPlaceNm, 1, true);
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_qeryList();
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save();
};

scwin.sbm_RetrieveRailroadWorkPlan_submit = function (e) {

};

scwin.sbm_RetrieveRailroadWorkPlan_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        var rowCnt = ds_RailroadWorkPlan.getRowCount();
        if( rowCnt == 0 ){
            await $c.gus.cfAlertMsg("[사유화차신청 정보] " + MSG_CM_ERR_003);
        }
        txt_totalRows.setValue(rowCnt);
        $c.gus.cfDisableBtn([]);
    }
};

scwin.sbm_RetrieveRailroadWorkPlan_submiterror = function (e) {

};

scwin.sbm_SaveRailroadWorkPlan_submit = function (e) {

};

scwin.sbm_SaveRailroadWorkPlan_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001); 
        scwin.f_qeryList();
    }
};

scwin.sbm_SaveRailroadWorkPlan_submiterror = function (e) {

};

scwin.gr_RailroadWorkPlan_oncellclick = function (Row, columnIndex, Colid) {
    if (Colid == "prvtAppCnt20Empty" || Colid == "prvtAppCnt20Full" || Colid == "prvtAppCnt40Empty" 
     || Colid == "prvtAppCnt40Full" || Colid == "prvtAppCnt45Empty" || Colid == "prvtAppCnt45Full"){
        if (ds_RailroadWorkPlan.getCellData(Row, "prvtAssgnFlag") == "N") {
			gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt20Empty", false);
			gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt40Empty", false);
			gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt45Empty", false);
			gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt20Full", false);
			gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt40Full", false);
			gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt45Full", false);
	    } else {
	   		if (scwin.CREATE_AUTH != "C") {
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt20Empty", true);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt40Empty", true);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt45Empty", true);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt20Full", true);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt40Full", true);
			    gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt45Full", true);
			} else {
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt20Empty", false);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt40Empty", false);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt45Empty", false);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt20Full", false);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt40Full", false);
				gr_RailroadWorkPlan.setCellReadOnly(Row, "prvtAppCnt45Full", false);			
			}
	    }
    }
};

scwin.gr_RailroadWorkPlan_oneditend = function (rowIndex, columnIndex, value) {
    scwin.oldData = ds_RailroadWorkPlan.getCellData(rowIndex, columnIndex);

};

scwin.udc_begintrainWorkPlace_callBackFunc = function(ref){
    //도착지코드          도착지명
    $c.gus.cfSetReturnValue(ref, ed_begintrainWorkPlaceCd, ed_begintrainWorkPlaceNm);

};

scwin.gr_RailroadWorkPlan_onafteredit = function (rowIndex, columnIndex, value) {
    var colId = gr_RailroadWorkPlan.getColumnID(columnIndex);
    if (colId == "xclsAppCnt20Empty"
     || colId == "xclsAppCnt20Full"
     || colId == "xclsAppCnt40Empty"
     || colId == "xclsAppCnt40Full"
     || colId == "xclsAppCnt45Empty"
     || colId == "xclsAppCnt45Full"
     || colId == "prvtAppCnt20Empty"
     || colId == "prvtAppCnt20Full"
     || colId == "prvtAppCnt40Empty"
     || colId == "prvtAppCnt40Full"
     || colId == "prvtAppCnt45Empty"
     || colId == "prvtAppCnt45Full"
     || colId == "frtcarAllocVol"
    ) {
        if (ds_RailroadWorkPlan.getCellData(rowIndex, colId) == "") {
            ds_RailroadWorkPlan.setCellData(rowIndex, colId, 0);
        }
    }
    scwin.f_internalCal1(rowIndex, colId, scwin.oldData);
};
